import CourseBuyCard from "../Components/CourseBuyCard";

function CoursePage() {
  return (
    <div>
      <div style={{background:"Black",color:"white",padding:"20px 40px"}}>
        <h2 style={{fontSize:"30px"}} >Name</h2>
        <p>Оценка:</p>
        <p>Автор:</p>
      </div>
      <div  style={{display:"flex", justifyContent:"space-between", padding:"40px"}}>
        <div style={{width:"60%"}}>
          <div style={{width:"80%",border:"1px solid #aaa", marginTop:"8px"}}>
            <p style={{fontSize:"24px"}}><b>Чему вы научитесь:</b></p> 
          </div>
        </div>
        <div style={{marginRight:"5%"}}>
          <CourseBuyCard/>
        </div>
      </div>
    </div>
  );
}

export default CoursePage;
